def evaluate_scent(p_relevance, value, cost=5):
    # Calculate if the user will 'Forage' this link
    utility = (p_relevance * value) - cost
    if utility > 5:
        return f"[Click] Utility={utility}"
    elif utility > 0:
        return f"[Maybe] Utility={utility}"
    else:
        return f"[Skip] Negative Utility={utility}"

print(f"Snippet 1 (Strong): {evaluate_scent(0.9, 50)}")
print(f"Snippet 2 (Vague): {evaluate_scent(0.1, 50)}")
